// ======================================================
// FORMAT FINAL API RESPONSE - Day 5 Production
// Builds clean JSON for Postman + Frontend + Logging
// ======================================================

// STEP 1: Get original request from Webhook
// User can send two formats:
// Format A: { "question": "...", "project": "Damac Hills 2" }
// Format B: { "question": "...", "filter": { "project": "Damac Hills 2" } } <- Your Postman uses this
const body = $('Webhook').first().json.body || {};

// STEP 2: Get data from Build Retrieval Context node
// This node already filtered docs, removed Emaar mixing, detected language
const retrieval = $('Build Retrieval Context').first().json || {};

// STEP 3: Determine final project name for response + logging
// Priority order (most reliable first):
// 1. User explicitly sent filter.project in Postman -> Use that
// 2. User sent project directly -> Use that
// 3. We auto-detected project from question (e.g., question contains "Bayview") -> Use retrieval.requested_project
// 4. We found project in top retrieved document -> Use retrieval.sources[0].project
// 5. Nothing found -> Fallback to "General" for FAQ / rules docs
const explicitProject = body.filter?.project || body.project || null;
const autoDetectedProject = retrieval.requested_project || null;
const foundInDocs = retrieval.sources?.[0]?.project || null;

const finalProject = explicitProject || autoDetectedProject || foundInDocs || "General";
// Examples:
// Q: "ما هي الدفعة الأولى؟" + filter: Damac Hills 2 -> finalProject = "Damac Hills 2" (explicit)
// Q: "What is the Bayview payment schedule?" (no filter) -> finalProject = "Bayview" (auto-detected from question)
// Q: "What is DLD fee?" (no filter, no project in question) -> finalProject = "General" (from doc metadata)

// STEP 4: Get Gemini answer
// $json is from "Generate Grounded Answer" node (Gemini 2.5 Flash)
// If Gemini failed or returned empty, show grounded fallback message
const answer =
  $json.candidates?.[0]?.content?.parts?.[0]?.text ||
  $input.first().json?.answer || // Fallback if skip_llm was true
  "I could not find this information in the uploaded documents.";

// STEP 5: Build final response object
// This is what Postman, your frontend, and Supabase logging will receive
return [{
  json: {
    // Original user question (keeps Arabic if Arabic was asked)
    question: retrieval.question || body.question || "",

    // Detected language: "ar" for Arabic, "en" for English
    // Comes from Detect Question Language node via Build Retrieval Context
    language: retrieval.language || "en",

    // Final project - now always correct, even when user sends no filter
    // Fixes your "General" bug in Supabase rag_logs_realestate table
    project: finalProject,

    // Final grounded answer from Gemini - ONLY using retrieved context
    answer: answer,

    // Source documents with citations - filtered to only relevant project
    // No more Emaar docs when you ask for Damac
    sources: retrieval.sources || [],

    // ISO timestamp for logging and frontend display
    timestamp: new Date().toISOString(),

    // Debug fields (optional, useful for Day 6 observability)
    // You can remove these before final publish if you want cleaner JSON
    _debug: {
      requested_filter: body.filter || {},
      auto_detected: autoDetectedProject,
      found_in_doc: foundInDocs
    }
  }
}];

const embedding = $json.embedding;
if (!embedding?.values || embedding.values.length!== 768) {
 throw new Error('Invalid embedding dimension. Expected 768, got ${embedding?.value?.length ?? 0}'
);
}
return [{
  json:{
 embedding_length: embedding.values.length,
 embedding: embedding.values,
  },
 },
];

// ============================================
// BUILD RETRIEVAL CONTEXT - Day 5 Production FIX
// Auto-detects project from question when filter is empty
// Handles English + Arabic questions
// ============================================

const MIN_SIMILARITY = 0.50;
const webhookBody = $('Webhook').first().json.body || {};
let requestedProject = webhookBody.filter?.project || webhookBody.project || "";

// STEP 2 FIX: Auto-detect project from question in BOTH English and Arabic
// This fixes "ما هو جدول الدفع لمشروع بايفيو؟" when you send NO filter
if (!requestedProject) {
  const q = (webhookBody.question || "").toLowerCase();

  // Bayview - English + Arabic variants (بايفيو، باي فيو، بايڤيو)
  if (q.includes("bayview") || q.includes("بايفيو") || q.includes("باي فيو") || q.includes("بايڤيو") || q.includes("باي") ) {
    requestedProject = "Bayview";
  }
  // Damac Hills 2 - English + Arabic
  else if (q.includes("damac hills 2") || q.includes("damac hills2") || q.includes("ضاحية داماك") || q.includes("داماك هيلز 2") || q.includes("داماك هيلز") || q.includes("داماك")) {
    requestedProject = "Damac Hills 2";
  }
  // DLD / Fees - keep as General (these are general docs, not a project)
  else if (q.includes("dld") || q.includes("رسوم") || q.includes("fee")) {
    requestedProject = "General";
  }
  // Add more projects here as you ingest them
  // else if (q.includes("marina")) requestedProject = "Dubai Marina";
}

let docs = ($json.body || []).filter(doc => doc.similarity >= MIN_SIMILARITY);

// STEP 3: Project Filtering - Now works even when filter is {}
if (requestedProject) {
  const matchingDocs = docs.filter(doc => {
    const docProject = (doc.metadata?.project || "").toLowerCase();
    return docProject === requestedProject.toLowerCase() || docProject.includes(requestedProject.toLowerCase());
  });
  if (matchingDocs.length > 0) {
    docs = matchingDocs;
  } else {
    const titleMatch = docs.filter(d => d.title.toLowerCase().includes(requestedProject.toLowerCase()));
    if (titleMatch.length > 0) docs = titleMatch;
  }
}

if (docs.length === 0) {
  return [{
    json: {
      question: webhookBody.question,
      language: $('Detect Question Language').first().json.detected_language,
      context: '',
      sources: [],
      skip_llm: true,
      detected_project: requestedProject || "General"
    }
  }];
}

// Deduplication
const seen = new Set(); const uniqueDocs = [];
for (const doc of docs) {
  const uniqueKey = `${doc.doc_id}`;
  if (!seen.has(uniqueKey)) { seen.add(uniqueKey); uniqueDocs.push(doc); }
}

// Diversity Limit - Max 2 chunks per doc
const MAX_CHUNKS_PER_DOCUMENT = 2;
const documentCounts = {}; const balancedDocs = [];
for (const doc of uniqueDocs) {
  const docId = doc.doc_id;
  if (!documentCounts[docId]) documentCounts[docId] = 0;
  if (documentCounts[docId] >= MAX_CHUNKS_PER_DOCUMENT) continue;
  documentCounts[docId]++; balancedDocs.push(doc);
}

// Re-sort by similarity AFTER filtering
balancedDocs.sort((a,b) => b.similarity - a.similarity);

const context = balancedDocs.map((doc, i) => {
  const m = doc.metadata||{};
  return `DOCUMENT ${i+1}\nTitle: ${doc.title}\nProject: ${m.project}\n${doc.content}`;
}).join("\n---\n");

return [{
  json: {
    question: webhookBody.question,
    language: $('Detect Question Language').first().json.detected_language,
    requested_project: requestedProject || "General",
    context,
    sources: balancedDocs.map(d => ({
      title: d.title,
      developer: d.metadata?.developer,
      project: d.metadata?.project,
      community: d.metadata?.community,
      document_type: d.metadata?.document_type,
      similarity: d.similarity
    })),
    skip_llm: false
  }
}];

return [{
  json: {
    webhook: $('Webhook').first().json.body,
    filter: (() => {
      const body = $('Webhook').first().json.body;

      const filter = {};

      if (body.project) filter.project = body.project;
      if (body.developer) filter.developer = body.developer;
      if (body.community) filter.community = body.community;
      if (body.document_type) filter.document_type = body.document_type;

      return filter;
    })()
  }
}];

const question = $json.body.question || "";

const isArabic = /[\u0600-\u06FF]/.test(question);

return [{
  json: {
    ...$json,
    detected_language: isArabic ? "ar" : "en"
  }
}];
